# 1. Заполняем профили для ВСЕХ авторов, если они есть в словаре 
for author, data in CONTENT.items():
    author_dir = os.path.join(base_dir, author)
    if not os.path.exists(author_dir): continue
    
    prof_path = os.path.join(author_dir, "профиль.json")
    if os.path.exists(prof_path):
        with open(prof_path, "r", encoding="utf-8") as f:
            prof = json.load(f)
        prof["биография"] = data["bio"]
        prof["книги"] = data["books"]
        with open(prof_path, "w", encoding="utf-8") as f:
            json.dump(prof, f, ensure_ascii=False, indent=2)

# 2. Генерируем идеи для 10 авторов (у которых 0 идей)
for author, data in CONTENT.items():
    author_dir = os.path.join(base_dir, author)
    if not os.path.exists(author_dir): continue
    
    info_path = os.path.join(author_dir, "инфо.json")
    with open(info_path, "r", encoding="utf-8") as f:
        info = json.load(f)
        
    group = info["группы"][0]
    cat = group["категории"][0]
    
    # Если идеи пустые:
    if len(cat["идеи"]) == 0:
        for idea_tpl in data["ideas"]:
            folder, title, text = idea_tpl
            idea_dir = os.path.join(author_dir, "идеи", folder)
            os.makedirs(os.path.join(idea_dir, "рисунки"), exist_ok=True)
            
            cat["идеи"].append(title)
            
            desc = {
                "текст": text,
                "описание": {"писание": text}
            }
            with open(os.path.join(idea_dir, "описание.json"), "w", encoding="utf-8") as f:
                json.dump(desc, f, ensure_ascii=False, indent=2)
                
    with open(info_path, "w", encoding="utf-8") as f:
        json.dump(info, f, ensure_ascii=False, indent=2)

print("Текстовые профили, книги и идеи (для пустых) успешно созданы!")
